// Parse the invoke args and pick a provider. Keyless MOCK is the default when no
// provider key is configured (mirrors tool-web-search's SEARCH_PROVIDER=mock default).
const body = msg.payload || {};
const query = typeof body.query === 'string' ? body.query : '';
// Public contract uses `count`; accept `max_results` as a drop-in alias. Clamp 1..20.
let count = body.count;
if (count === undefined || count === null) count = body.max_results;
count = parseInt(count, 10);
if (!Number.isFinite(count) || count < 1) count = 5;
if (count > 20) count = 20;

const provider = (env.get('SEARCH_PROVIDER') || 'mock').toLowerCase();
const serpKey = env.get('SERPAPI_API_KEY');
const braveKey = env.get('BRAVE_SEARCH_API_KEY') || env.get('BRAVE_API_KEY');

let mode = 'mock';
let selected = 'mock';
if (provider === 'serpapi' && serpKey) { mode = 'provider'; selected = 'serpapi'; }
else if (provider === 'brave' && braveKey) { mode = 'provider'; selected = 'brave'; }

msg.ws = { query: query, count: count, provider: selected };
msg.mode = mode;
return msg;

// Build the outbound provider request using the PLATFORM runtime's provider key (env).
const q = msg.ws.query;
const n = msg.ws.count;
if (msg.ws.provider === 'serpapi') {
  const key = env.get('SERPAPI_API_KEY') || '';
  const base = env.get('SERPAPI_BASE_URL') || 'https://serpapi.com/search.json';
  msg.url = base + '?engine=google&q=' + encodeURIComponent(q) + '&num=' + n + '&api_key=' + encodeURIComponent(key);
  msg.method = 'GET';
  msg.headers = { 'Accept': 'application/json' };
} else {
  const key = env.get('BRAVE_SEARCH_API_KEY') || env.get('BRAVE_API_KEY') || '';
  const base = env.get('BRAVE_BASE_URL') || 'https://api.search.brave.com/res/v1/web/search';
  msg.url = base + '?q=' + encodeURIComponent(q) + '&count=' + n;
  msg.method = 'GET';
  msg.headers = { 'Accept': 'application/json', 'X-Subscription-Token': key };
}
msg.payload = {};
return msg;

// Map the provider payload to the tool-web-search output shape:
//   { results: [ { title, url, snippet, rank } ] }
const n = (msg.ws && msg.ws.count) || 5;
const provider = (msg.ws && msg.ws.provider) || 'serpapi';
const payload = msg.payload || {};
let results = [];
if (provider === 'serpapi') {
  const organic = Array.isArray(payload.organic_results) ? payload.organic_results : [];
  results = organic.slice(0, n).map(function (it, i) {
    return {
      title: String(it.title || ''),
      url: String(it.link || ''),
      snippet: String(it.snippet || ''),
      rank: parseInt(it.position, 10) || (i + 1)
    };
  });
} else {
  const web = (payload.web && Array.isArray(payload.web.results)) ? payload.web.results : [];
  results = web.slice(0, n).map(function (it, i) {
    return {
      title: String(it.title || ''),
      url: String(it.url || ''),
      snippet: String(it.description || ''),
      rank: i + 1
    };
  });
}
msg.payload = { results: results };
msg.statusCode = 200;
msg.headers = { 'Content-Type': 'application/json' };
return msg;

// Deterministic, network-free canned results — same query always yields the same output,
// mirroring tool-web-search's mock provider so local/dev runs keyless exactly like the fixtures.
const q = msg.ws.query;
const n = msg.ws.count;
const results = [];
for (let i = 0; i < n; i++) {
  const rank = i + 1;
  results.push({
    title: 'Result ' + rank + ' for ' + q,
    url: 'https://example.com/search?q=' + q + '&r=' + rank,
    snippet: 'This is a deterministic mock snippet #' + rank + " describing results for the query '" + q + "'.",
    rank: rank
  });
}
msg.payload = { results: results };
msg.statusCode = 200;
msg.headers = { 'Content-Type': 'application/json' };
return msg;
